let modalTimer;function showModal(message,isSuccess){const modal=document.getElementById("statusModal");const modalMessage=document.getElementById("modalMessage");if(modal&&modalMessage){if(modalTimer)clearTimeout(modalTimer);modalMessage.textContent=message;modal.style.display="block";if(isSuccess){modalTimer=setTimeout(function(){closeModal();},5000);}}}
function closeModal(){const modal=document.getElementById("statusModal");const modalMessage=document.getElementById("modalMessage");if(modal){modal.style.display="none";if(modalTimer)clearTimeout(modalTimer);const form=document.querySelector("#contactForm, #commentForm");if(form)form.reset();const isBlogPage=window.location.pathname.includes('/blog/');const isAdminPage=window.location.pathname.includes('/admin/');const isSuccessMessage=modalMessage&&(modalMessage.textContent.includes("Thank you")||modalMessage.textContent.includes("successfully")||modalMessage.textContent.includes("Comment approved")||modalMessage.textContent.includes("Comment unapproved")||modalMessage.textContent.includes("Comment archived")||modalMessage.textContent.includes("Comment restored"));if(isSuccessMessage&&(isBlogPage||isAdminPage)){window.location.reload();}}}
async function handleAjaxAction(event,form){event.preventDefault();try{const response=await fetch(form.action,{method:'POST',headers:{'X-Requested-With':'XMLHttpRequest'}});const data=await response.json();showModal(data.message,data.success);}catch(error){console.error("Action error:",error);showModal("An error occurred. Please try again.",false);}}
function initModal(){const modal=document.getElementById("statusModal");const span=document.querySelector(".close-btn");if(!modal||!span)return;span.onclick=function(){closeModal();}
window.onclick=function(event){if(event.target==modal){closeModal();}}}
document.addEventListener('DOMContentLoaded',initModal);function closeFlash(element){element.style.opacity='0';setTimeout(()=>element.remove(),500);}
document.addEventListener('DOMContentLoaded',function(){setTimeout(function(){const modals=document.querySelectorAll('.flash-modal');modals.forEach(modal=>closeFlash(modal));},5000);});